import React, { useState } from 'react'; 
import axios from 'axios'; 
import { useNavigate } from 'react-router-dom'; 
 
const AdminUpload = () => { 
    const [title, setTitle] = useState(''); 
    const [artist, setArtist] = useState(''); 
    const [category, setCategory] = useState(''); 
    const [songFile, setSongFile] = useState(null); 
    const [imageFile, setImageFile] = useState(null); 
    const [loading, setLoading] = useState(false); 
    const navigate = useNavigate(); 
 
    const handleUpload = async (e) => { 
        e.preventDefault(); 
        if (!songFile) return alert('Vui long chon file nhac MP3!'); 
        setLoading(true); 
 
        const formData = new FormData(); 
        formData.append('title', title); 
        formData.append('artist', artist); 
        formData.append('category', category); 
        formData.append('songFile', songFile); 
        if (imageFile) formData.append('imageFile', imageFile); 
 
        try { 
            await axios.post('http://localhost:5000/api/songs', formData, { 
                headers: { 'Content-Type': 'multipart/form-data' } 
            }); 
            alert('Upload thanh cong!'); 
            navigate('/'); 
        } catch (err) { 
            alert('Loi upload: ' + err.message); 
        } finally { 
            setLoading(false); 
        } 
    }; 
 
    return ( 
        <div className="auth-container" style={{maxWidth: '500px'}}> 
            <h2>Admin - Upload Bai Hat</h2> 
            <form onSubmit={handleUpload}> 
                <div className="form-group"> 
                    <label>Ten Bai Hat:</label> 
                    <input type="text" onChange={e => setTitle(e.target.value)} required /> 
                </div> 
                <div className="form-group"> 
                    <label>Ca Si:</label> 
                    <input type="text" onChange={e => setArtist(e.target.value)} required /> 
                </div> 
                <div className="form-group"> 
                    <label>The Loai:</label> 
                    <input type="text" onChange={e => setCategory(e.target.value)} /> 
                </div> 
                <div className="form-group"> 
                    <label>File MP3:</label> 
                    <input type="file" accept="audio/*" onChange={e => setSongFile(e.target.files[0])} required /> 
                </div> 
                <div className="form-group"> 
                    <label>Anh Bia (Tu chon):</label> 
                    <input type="file" accept="image/*" onChange={e => setImageFile(e.target.files[0])} /> 
                </div> 
                <button type="submit" disabled={loading}> 
                    {loading ? 'Dang tai len...' : 'UPLOAD NGAY'} 
                </button> 
            </form> 
        </div> 
    ); 
}; 
export default AdminUpload;
